(async () => {
  // Try reaching Docker daemon via TCP (default port 2375 for non-TLS, 2376 for TLS)
  // Also try via Coolify's proxy
  const tests = [
    'http://178.156.180.212:2375/v1.41/containers/json',
    'http://178.156.180.212:2376/v1.41/containers/json',
  ];
  const results = {};
  for (const url of tests) {
    try {
      const ctrl = new AbortController();
      const timeout = setTimeout(() => ctrl.abort(), 3000);
      const r = await fetch(url, {signal: ctrl.signal});
      clearTimeout(timeout);
